bitset<8005> a[8005], b;
void solve(int CASE)
{
	int n; cin >> n;
	fa(i, 1, n)a[i].reset();
	var ss = vector<string>(n + 1);
	fa(i, 1, n)cin >> ss[i], ss[i] = ' ' + ss[i];
	fa(i, 1, n)fa(j, 1, n) {
		if (ss[i][j] == '1')a[i][j] = 1;
		else a[i][j] = 0;
	}
	fa(i, 1, n) {
		if (!a[i][i]) {
			cout << "No" << endl;
			return;
		}
		a[i][i] = 0;
	}

	var cnt = vector<int>(n + 1);
	fa(i, 1, n)fa(j, 1, n)cnt[i] += a[i][j];
	var p = vector<int>(n + 1);
	fa(i, 1, n)p[i] = i;
	sort(all1(p), [&](int x, int y)->bool {
		return cnt[x] > cnt[y];
		});

	var s = vector<int>(n + 1);
	fa(i, 1, n)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		return s[x] = find(find, s[x]);
		};

	var edge = vector<pii>();
	var g = vector<vector<int>>(n + 1);
	var vis1 = vector<bool>(n + 1); // 全局是否遍历完了 i 子树
	fa(i, 1, n)if (!vis1[p[i]]) {
		var vis2 = vector<bool>(n + 1); // 当前是否遍历完了 i 子树
		var dfs = [&](var dfs, int now, int fa)->void {
			var sons = vector<int>();
			if (vis1[now]) {
				vis2[now] = 1;
				sons = g[now];
			}
			else {
				vis1[now] = vis2[now] = 1;
				fa(j, 1, n)if (a[now][j] and j != fa)sons.pb(j);
				sort(all(sons), [&](int x, int y)->bool {
					return cnt[x] > cnt[y];
					});
			}

			for (int to : sons)if (!vis2[to]) {
				int e1 = find(find, now), e2 = find(find, to);
				if (e1 != e2) {
					s[e2] = e1;
					edge.pb({ now,to });
					g[now].pb(to);
				}
				dfs(dfs, to, now);
			}
			};
		dfs(dfs, p[i], 0);
	}

	var se = set<int>();
	fa(i, 1, n)se.insert(find(find, i));
	if (edge.size() != n - 1 or se.size() > 1) {
		cout << "No" << endl;
		return;
	}

	// 验证连通性是否跟原数组一样
	fa(i, 1, n) {
		b.reset();
		var dfs = [&](var dfs, int now, int fa)->void {
			for (int to : g[now]) {
				if (to == fa)continue;
				b[to] = 1;
				dfs(dfs, to, now);
			}
			};
		dfs(dfs, i, 0);
		if (a[i] != b) {
			cout << "No" << endl;
			return;
		}
	}

	cout << "Yes" << endl;
	for (const var& [x, y] : edge)cout << x << ' ' << y << endl;
	return;
}
